  ($lum$0ab36e90-d793-5048-a860-3de9602c85e6$lum$::uuid, $lum$prompting$lum$, $lum$Prompting$lum$, $lum$topic$lum$),
  ($lum$19bc75db-e505-589c-9dcd-c946497db8e0$lum$::uuid, $lum$framing$lum$, $lum$Framing & briefs$lum$, $lum$topic$lum$),
