  ($lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, $lum$c9005d52-5c35-5b16-b795-f53adf3b1a99$lum$::uuid),
  ($lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, $lum$0817572c-d973-5e8f-a4a5-0044528791d9$lum$::uuid),
  ($lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, $lum$458418e5-8af2-5640-ad4e-0439bfa1c1f8$lum$::uuid),
  ($lum$6176690d-cee6-529a-ab80-6064ee4e0185$lum$::uuid, $lum$c9005d52-5c35-5b16-b795-f53adf3b1a99$lum$::uuid),
